135	impl Wait for ShmProviderState {
136	    fn wait(self) -> <Self as Resolvable>::To {
137	        match self {
138	            ShmProviderState::Ready(provider) => Some(provider),
139	            ShmProviderState::Initializing(receiver) => receiver.recv().ok().flatten(),
140	            ShmProviderState::Disabled | ShmProviderState::Error => None,
141	        }
142	    }
