145	#[cfg(feature = "shared-memory")]
146	#[zenoh_macros::unstable]
147	impl IntoFuture for ShmProviderState {
148	    type Output = <Self as Resolvable>::To;
149	    type IntoFuture = std::pin::Pin<Box<dyn Future<Output = <Self as IntoFuture>::Output> + Send>>;
150	
151	    fn into_future(self) -> Self::IntoFuture {
152	        Box::pin(async move {
153	            match self {
154	                ShmProviderState::Ready(provider) => Some(provider),
155	                ShmProviderState::Initializing(receiver) => {
156	                    receiver.recv_async().await.ok().flatten()
157	                }
158	                ShmProviderState::Disabled | ShmProviderState::Error => None,
159	            }
160	        })
161	    }
