295	    fn get_transports(&self) -> Box<dyn Iterator<Item = Transport> + Send + Sync> {
296	        let unicast_transports = zenoh_runtime::ZRuntime::Net
297	            .block_in_place(self.manager.get_transports_unicast())
298	            .into_iter()
299	            .filter_map(|t| t.get_peer().ok())
300	            .map(|ref peer| Transport::new(peer, false));
301	
302	        let multicast_transports = zenoh_runtime::ZRuntime::Net
303	            .block_in_place(self.manager.get_transports_multicast())
304	            .into_iter()
305	            .flat_map(|t| t.get_peers().ok().unwrap_or_default())
306	            .map(|ref peer| Transport::new(peer, true));
307	
308	        Box::new(unicast_transports.chain(multicast_transports))
309	    }
310	
311	    fn get_transports_blocking(&self) -> Vec<Transport> {
312	        self.manager
313	            .get_transports_unicast_blocking()
314	            .into_iter()
315	            .filter_map(|t| t.get_peer().ok())
316	            .map(|peer| Transport::new(&peer, false))
317	            .chain(
318	                self.manager
319	                    .get_transports_multicast_blocking()
320	                    .into_iter()
321	                    .flat_map(|t| t.get_peers().ok().unwrap_or_default())
322	                    .map(|peer| Transport::new(&peer, true)),
323	            )
324	            .collect()
325	    }
