514	    fn get_links_all(&self) -> Box<dyn Iterator<Item = Link> + Send + Sync> {
515	        let peer_to_links = |peer: TransportPeer| -> Vec<Link> {
516	            let zid: ZenohId = peer.zid.into();
517	            let is_qos = peer.is_qos;
518	            peer.links
519	                .into_iter()
520	                .map(|ref link| Link::new(zid, link, is_qos))
521	                .collect()
522	        };
523	
524	        let unicast_links = self
525	            .get_transports_unicast_peers()
526	            .into_iter()
527	            .flat_map(peer_to_links);
528	
529	        let multicast_links = self
530	            .get_transports_multicast_peers()
531	            .into_iter()
532	            .flatten()
533	            .flat_map(peer_to_links);
534	
535	        Box::new(unicast_links.chain(multicast_links))
536	    }
